const Validate = {
  NAME_RE: /^[a-z][a-z0-9_]*$/,
  polygonName(name, ws) {
    const issues = [];
    if (!name) issues.push({ level: 'error', field: 'name', message: 'Zone name is required.' });
    else if (!this.NAME_RE.test(name)) issues.push({ level: 'error', field: 'name', message: 'Use lowercase letters, digits, underscores; must start with a letter.' });
    if (ws.cameras.some(c => c.name === name)) issues.push({ level: 'error', field: 'name', message: 'A zone cannot share a camera\u2019s name.' });
    return issues;
  },
  polygon(poly) {
    const issues = [];
    if (poly.points.length < 3) issues.push({ level: 'error', field: 'points', message: 'A polygon needs at least 3 points.' });
    if (poly.points.some(p => p.x < 0 || p.x > 1 || p.y < 0 || p.y > 1)) issues.push({ level: 'warn', field: 'points', message: `\u201c${poly.name}\u201d has coordinates outside 0.0\u20131.0.` });
    return issues;
  }
};

const Toast = {
  _timer: null, _undoFn: null,
  show(message, undoFn) {
    this._finalize();
    this._undoFn = undoFn;
    const el = document.getElementById('toast');
    el.querySelector('.toast-msg').textContent = message;
    el.classList.add('visible');
    this._timer = setTimeout(() => this._finalize(), 5000);
  },
  undo() { if (this._undoFn) this._undoFn(); this._finalize(); },
  _finalize() { clearTimeout(this._timer); this._undoFn = null; document.getElementById('toast')?.classList.remove('visible'); }
};
